defmodule MyAppWeb.SoapController do
  use MyAppWeb, :controller
  import SweetXml

  def process_soap(conn, _params) do
    {:ok, body, conn} = Plug.Conn.read_body(conn)
    
    parsed_data = parse_xml_safely(body)
    
    json(conn, %{result: parsed_data})
  end

  defp parse_xml_safely(xml_string) do
    try do
      sanitized_xml = sanitize_xml(xml_string)
      
      sanitized_xml
      |> xmap(
        envelope: ~x"//soap:Envelope"o,
        body: ~x"//soap:Body/*"o |> transform_by(&extract_node_data/1),
        header: ~x"//soap:Header/*"o |> transform_by(&extract_node_data/1)
      )
    rescue
      e -> %{error: "XML parsing failed: #{inspect(e)}"}
    end
  end

  defp sanitize_xml(xml_string) do
    xml_string
    |> String.replace(~r/<!DOCTYPE[^>]*>/i, "")
    |> String.replace(~r/<!ENTITY[^>]*>/i, "")
    |> String.replace(~r/<!\[CDATA\[.*?\]\]>/s, fn match ->
      match
      |> String.replace("<!ENTITY", "")
      |> String.replace("SYSTEM", "")
    end)
  end

  defp extract_node_data(nil), do: nil
  defp extract_node_data(node) do
    case node do
      xmlElement() ->
        %{
          name: xmlElement(node, :name) |> to_string(),
          content: xmlElement(node, :content) |> extract_content()
        }
      _ -> nil
    end
  end

  defp extract_content(content) when is_list(content) do
    Enum.map(content, fn item ->
      case item do
        xmlText() -> xmlText(item, :value) |> to_string() |> String.trim()
        xmlElement() -> extract_node_data(item)
        _ -> nil
      end
    end)
    |> Enum.reject(&is_nil/1)
  end
  defp extract_content(_), do: []
end

defmodule MyAppWeb.SecureSoapController do
  use MyAppWeb, :controller

  def process_soap(conn, _params) do
