        conn
        |> put_status(:bad_request)
        |> json(%{error: reason})
    end
  end

  defp parse_xml_with_sax(xml_string) do
    try do
      options = [
        continuation_fun: fn more_data, state -> {more_data, state} end,
        event_fun: &handle_sax_event/3,
        event_state: %{
          stack: [],
          result: %{},
          current_path: [],
          reject: false
        }
      ]

      case :xmerl_sax_parser.stream(xml_string, options) do
        {:ok, state, _} ->
          if state.reject do
            {:error, "Potentially malicious XML detected"}
          else
            {:ok, state.result}
          end
        {:error, reason} ->
          {:error, "XML parsing error: #{inspect(reason)}"}
      end
    rescue
      e -> {:error, "Exception during parsing: #{inspect(e)}"}
    end
  end

  defp handle_sax_event({:startElement, _, "DOCTYPE", _, _}, _, state) do
    %{state | reject: true}
  end

  defp handle_sax_event({:startElement, _, "ENTITY", _, _}, _, state) do
    %{state | reject: true}
  end

  defp handle_sax_event({:startElement, _uri, local_name, _qname, attributes}, _, state) do
    if Enum.any?(attributes, fn {_, _, attr_name, _} -> 
      String.contains?(to_string(attr_name), ["SYSTEM", "PUBLIC", "ENTITY"])
    end) do
      %{state | reject: true}
    else
      %{state | 
        stack: [{local_name, ""} | state.stack],
        current_path: [local_name | state.current_path]
      }
    end
  end

  defp handle_sax_event({:characters, chars}, _, %{reject: true} = state), do: state

  defp handle_sax_event({:characters, chars}, _, state) do
    case state.stack do
      [{tag, content} | rest] ->
        %{state | stack: [{tag, content <> to_string(chars)} | rest]}
      [] ->
        state
    end
  end

  defp handle_sax_event({:endElement, _uri, local_name, _qname}, _, %{reject: true} = state), do: state

  defp handle_sax_event({:endElement, _uri, local_name, _qname}, _, state) do
    case state.stack do
      [{^local_name, content} | rest] ->
        path = Enum.reverse(state.current_path)
        result = put_in_nested(state.result, path, String.trim(content))
        %{state | 
          stack: rest,
          current_path: tl(state.current_path),
          result: result
        }
      _ ->
        state
    end
  end

  defp handle_sax_event(_event, _, state), do: state

  defp put_in_nested(map, [key], value) do
    Map.put(map, to_string(key), value)
  end

  defp put_in_nested(map, [key | rest], value) do
    key_str = to_string(key)
    nested = Map.get(map, key_str, %{})
    Map.put(map, key_str, put_in_nested(nested, rest, value))
  end
